export interface GenerationConfig {
  apiKey: string;
  prompt: string;
  model: string;
  seconds: string;
  size: string;
  watermark: string;
  startImage: File | null;
  endImage: File | null;
}

export interface ApiResponse {
  id?: string;
  task_id?: string;
  code?: number;
  message?: string;
  data?: any;
  output?: {
    video_url?: string;
  };
}

export enum GenerationStatus {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  FAILED = 'FAILED',
}

export interface LogEntry {
  timestamp: string;
  message: string;
  type: 'info' | 'success' | 'error' | 'warning';
}

import { GenerationConfig, LogEntry } from '../types';

export const generateVideo = async (
  config: GenerationConfig,
  onLog: (log: LogEntry) => void
): Promise<any> => {
  const myHeaders = new Headers();
  myHeaders.append("Authorization", `Bearer ${config.apiKey}`);

  const formdata = new FormData();
  formdata.append("model", config.model);
  formdata.append("prompt", config.prompt);
  formdata.append("seconds", config.seconds);
  formdata.append("size", config.size);
  formdata.append("watermark", config.watermark);

  // Handle Start Image (Required for this flow)
  if (config.startImage) {
    onLog({
      timestamp: new Date().toLocaleTimeString(),
      message: `Attaching start frame: ${config.startImage.name}`,
      type: 'info'
    });
    // Matches the "input_reference" from the user snippet
    formdata.append("input_reference", config.startImage);
  }

  // Handle End Image (Optional/Experimental based on API support)
  // Note: The snippet only showed 'input_reference'. 
  // Standard Veo often uses 'last_frame' or similar. 
  // We append it if present, hoping the API endpoint supports the standard parameter.
  if (config.endImage) {
    onLog({
      timestamp: new Date().toLocaleTimeString(),
      message: `Attaching end frame: ${config.endImage.name}`,
      type: 'info'
    });
    // Common parameter name for end frames in video generation APIs
    formdata.append("input_reference_end", config.endImage); 
  }

  const requestOptions: RequestInit = {
    method: 'POST',
    headers: myHeaders,
    body: formdata,
    redirect: 'follow'
  };

  onLog({
    timestamp: new Date().toLocaleTimeString(),
    message: 'Sending request to https://api.apizoo.top/v1/videos...',
    type: 'info'
  });

  try {
    const response = await fetch("https://api.apizoo.top/v1/videos", requestOptions);

    if (!response.ok) {
        const errText = await response.text();
        throw new Error(`API Error (${response.status}): ${errText}`);
    }

    const resultText = await response.text();

    try {
        // Try to parse JSON if possible, otherwise return text
        return JSON.parse(resultText);
    } catch (e) {
        return resultText;
    }

  } catch (error: any) {
    onLog({
      timestamp: new Date().toLocaleTimeString(),
      message: `Network/API Error: ${error.message}`,
      type: 'error'
    });
    throw error;
  }
};

import React from 'react';
import { Upload } from 'lucide-react';

export const Label: React.FC<{ children: React.ReactNode }> = ({ children }) => (
