import { GenerationConfig, LogEntry } from '../types';

export const generateVideo = async (
  config: GenerationConfig,
  onLog: (log: LogEntry) => void
): Promise<any> => {
  const myHeaders = new Headers();
  myHeaders.append("Authorization", `Bearer ${config.apiKey}`);

  const formdata = new FormData();
  formdata.append("model", config.model);
  formdata.append("prompt", config.prompt);
  formdata.append("seconds", config.seconds);
  formdata.append("size", config.size);
  formdata.append("watermark", config.watermark);

  // Handle Start Image
  if (config.startImage) {
    onLog({
      timestamp: new Date().toLocaleTimeString(),
      message: `Attaching start frame [input_reference]: ${config.startImage.name}`,
      type: 'info'
    });
    formdata.append("input_reference", config.startImage);
  }

  // Handle End Image
  if (config.endImage) {
    const paramName = config.endFrameParamName || "input_reference"; // Default to input_reference (Array mode)
    const isArrayMode = paramName === "input_reference";

    onLog({
      timestamp: new Date().toLocaleTimeString(),
      message: isArrayMode 
        ? `Attaching end frame [input_reference]: ${config.endImage.name} (Sequence Mode)`
        : `Attaching end frame [${paramName}]: ${config.endImage.name}`,
      type: 'info'
    });

    formdata.append(paramName, config.endImage); 
  }

  const requestOptions: RequestInit = {
    method: 'POST',
    headers: myHeaders,
    body: formdata,
    redirect: 'follow'
  };

  onLog({
    timestamp: new Date().toLocaleTimeString(),
    message: 'Sending request to https://api.apizoo.top/v1/videos...',
    type: 'info'
  });

  try {
    const response = await fetch("https://api.apizoo.top/v1/videos", requestOptions);

    if (!response.ok) {
        const errText = await response.text();
        throw new Error(`API Error (${response.status}): ${errText}`);
    }

    const resultText = await response.text();

    try {
        // Try to parse JSON if possible, otherwise return text
        return JSON.parse(resultText);
    } catch (e) {
        return resultText;
    }

  } catch (error: any) {
    onLog({
      timestamp: new Date().toLocaleTimeString(),
      message: `Network/API Error: ${error.message}`,
      type: 'error'
    });
    throw error;
  }
};

export interface GenerationConfig {
  apiKey: string;
  prompt: string;
  model: string;
  seconds: string;
  size: string;
  watermark: string;
  startImage: File | null;
  endImage: File | null;
  endFrameParamName: string; // New field for customizable parameter name
}

export interface ApiResponse {
  id?: string;
  task_id?: string;
  code?: number;
  message?: string;
  data?: any;
  output?: {
    video_url?: string;
  };
}

export enum GenerationStatus {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  FAILED = 'FAILED',
}

export interface LogEntry {
  timestamp: string;
  message: string;
  type: 'info' | 'success' | 'error' | 'warning';
}

export interface HistoryItem {
  id: string;
  timestamp: number;
  prompt: string;
  model: string;
  status: GenerationStatus;
  videoUrl?: string;
  thumbnailUrl?: string; // Optional: could be the start image URL if we object-url it
  error?: string;
}

