import { GenerationConfig, LogEntry } from '../types';

const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper function to poll the status of the task
const pollTaskStatus = async (
  taskId: string, 
  apiKey: string, 
  onLog: (log: LogEntry) => void
): Promise<any> => {
  const maxAttempts = 120; // Try for about 6 minutes (120 * 3s)
  const interval = 3000; // 3 seconds

  const myHeaders = new Headers();
  myHeaders.append("Accept", "application/json");
  myHeaders.append("Authorization", `Bearer ${apiKey}`);

  const requestOptions: RequestInit = {
    method: 'GET',
    headers: myHeaders,
    redirect: 'follow'
  };

  for (let i = 0; i < maxAttempts; i++) {
    await wait(interval);

    try {
      const response = await fetch(`https://api.apizoo.top/v1/videos/${taskId}`, requestOptions);

      if (!response.ok) {
        onLog({
          timestamp: new Date().toLocaleTimeString(),
          message: `Polling HTTP Error: ${response.status}. Retrying...`,
          type: 'warning'
        });
        continue;
      }

      const result = await response.json();

      // Determine Status
      // ApiZoo / Sora models usually return 'status' or 'state'
      // Possible values: 'processing', 'pending', 'succeeded', 'failed', 'completed'
      const status = (result.status || result.state || '').toLowerCase();
      const progress = result.progress ? ` (${result.progress}%)` : '';

      if (status === 'succeeded' || status === 'completed') {
        onLog({
          timestamp: new Date().toLocaleTimeString(),
          message: `Task Finished!`,
          type: 'success'
        });
        return result; // Return the full final object which should contain video_url
      } else if (status === 'failed' || status === 'error') {
        throw new Error(result.message || result.error || "Task failed on server.");
      } else {
        // Still processing
        if (i % 3 === 0) { // Log every ~9 seconds to avoid clutter
            onLog({
            timestamp: new Date().toLocaleTimeString(),
            message: `Task is ${status || 'processing'}...${progress}`,
            type: 'info'
            });
        }
      }

      // If we have a video_url directly, we can also consider it done
      if (result.output?.video_url || result.video_url || result.url) {
        return result;
      }

    } catch (error: any) {
      console.error("Polling error", error);
      // Don't throw immediately on network glitches during polling, just log and retry
      onLog({
        timestamp: new Date().toLocaleTimeString(),
        message: `Polling check failed: ${error.message}`,
        type: 'warning'
      });
    }
  }

  throw new Error("Timeout: Video generation took too long.");
};

export const generateVideo = async (
  config: GenerationConfig,
  onLog: (log: LogEntry) => void
): Promise<any> => {
  const myHeaders = new Headers();
  myHeaders.append("Authorization", `Bearer ${config.apiKey}`);
  // Note: Do not manually set Content-Type to multipart/form-data, 
  // let the browser set it with the boundary when using FormData.

  const formdata = new FormData();
  formdata.append("model", config.model);
  formdata.append("prompt", config.prompt);
  formdata.append("seconds", config.seconds);
  formdata.append("size", config.size);
  formdata.append("watermark", config.watermark);

  // Handle Start Image
  if (config.startImage) {
    onLog({
      timestamp: new Date().toLocaleTimeString(),
      message: `Uploading start frame [input_reference]: ${config.startImage.name}`,
      type: 'info'
    });
    formdata.append("input_reference", config.startImage);
  }

  // Handle End Image
  if (config.endImage) {
    const paramName = config.endFrameParamName || "input_reference";
    onLog({
      timestamp: new Date().toLocaleTimeString(),
      message: `Uploading end frame [${paramName}]: ${config.endImage.name}`,
      type: 'info'
    });
    formdata.append(paramName, config.endImage); 
  }

  const requestOptions: RequestInit = {
    method: 'POST',
    headers: myHeaders,
    body: formdata,
    redirect: 'follow'
  };

  onLog({
    timestamp: new Date().toLocaleTimeString(),
    message: 'Submitting task to ApiZoo...',
    type: 'info'
  });

  // 1. Submit the Task
  let initialResponse;
  try {
    const response = await fetch("https://api.apizoo.top/v1/videos", requestOptions);
    if (!response.ok) {
        const errText = await response.text();
        throw new Error(`Submission Failed (${response.status}): ${errText}`);
    }
    initialResponse = await response.json();
  } catch (error: any) {
    onLog({ timestamp: new Date().toLocaleTimeString(), message: `Submit Error: ${error.message}`, type: 'error' });
    throw error;
  }

  // 2. Check for Task ID and Poll
  // The API usually returns { id: "..." } or { task_id: "..." }
  const taskId = initialResponse.id || initialResponse.task_id;

  if (taskId) {
    onLog({
        timestamp: new Date().toLocaleTimeString(),
        message: `Task Submitted Successfully. ID: ${taskId}`,
        type: 'success'
    });
    onLog({
        timestamp: new Date().toLocaleTimeString(),
        message: `Waiting for generation (this may take 1-3 minutes)...`,
        type: 'info'
    });

    // Start Polling
    return await pollTaskStatus(taskId, config.apiKey, onLog);
  } else if (initialResponse.output?.video_url || initialResponse.data) {
    // If by chance it returns synchronously (unlikely for video but possible)
    return initialResponse;
  } else {
    // Unknown response format
    onLog({
        timestamp: new Date().toLocaleTimeString(),
        message: `Warning: No Task ID found in response. Check logs.`,
        type: 'warning'
    });
    console.log("Unknown response:", initialResponse);
    return initialResponse;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Settings, Play, Terminal, Loader2, Video, ImageIcon, AlertCircle, Download, History, Trash2, Clock, CheckCircle2, XCircle, Key, ExternalLink, AlertTriangle } from 'lucide-react';
import { generateVideo } from './services/apiService';
import { GenerationConfig, LogEntry, GenerationStatus, HistoryItem } from './types';
import { Input, Label, Select, FileUploadZone } from './components/UiComponents';

const MODEL_OPTIONS = [
  "veo_3_1-fast-4K",
  "veo_3_1-components-4K",
  "veo_3_1-4K",
  "veo_3_1-fast-components-4K",
  "veo_3_1",
  "veo_3_1-fast",
  "veo_3_1-components"
];

const App: React.FC = () => {
  // Config State
  const [apiKey, setApiKey] = useState(() => {
    return localStorage.getItem('user_api_key') || "";
  });

  const [model, setModel] = useState(MODEL_OPTIONS[0]);
  const [prompt, setPrompt] = useState("生成视频"); 
  const [seconds, setSeconds] = useState("8");
  const [size, setSize] = useState("16x9");
  const [watermark, setWatermark] = useState("false");
  const [startImage, setStartImage] = useState<File | null>(null);
  const [endImage, setEndImage] = useState<File | null>(null);

  // Advanced Config
  const [endFrameParamName] = useState("input_reference");

  // App State
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [currentVideoUrl, setCurrentVideoUrl] = useState<string | null>(null);
  // Store the raw response to debug if video is missing
  const [lastResponse, setLastResponse] = useState<any>(null);

  const [showSettings, setShowSettings] = useState(false);
  const [elapsedTime, setElapsedTime] = useState(0);

  // History State
  const [history, setHistory] = useState<HistoryItem[]>(() => {
    try {
      const saved = localStorage.getItem('veo_history');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  useEffect(() => {
    localStorage.setItem('veo_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('user_api_key', apiKey);
  }, [apiKey]);

  // Timer logic
  useEffect(() => {
    let interval: any;
    if (status === GenerationStatus.PROCESSING) {
      interval = setInterval(() => {
        setElapsedTime(prev => prev + 1);
      }, 1000);
    } else {
      clearInterval(interval);
    }
    return () => clearInterval(interval);
  }, [status]);

  const addLog = (entry: LogEntry) => {
    setLogs(prev => [...prev, entry]);
  };

  const handleGenerate = async () => {
    if (!apiKey) {
      addLog({ timestamp: new Date().toLocaleTimeString(), message: "Error: Please enter your API Key in Settings.", type: 'error' });
      setShowSettings(true); 
      alert("Please enter your API Key first.");
      return;
    }

    if (!startImage) {
      addLog({ timestamp: new Date().toLocaleTimeString(), message: "Error: Start image is required.", type: 'error' });
      return;
    }

    setStatus(GenerationStatus.PROCESSING);
    setLogs([]); 
    setCurrentVideoUrl(null);
    setLastResponse(null);
    setElapsedTime(0);

    const newHistoryId = Date.now().toString();
    const newHistoryItem: HistoryItem = {
      id: newHistoryId,
      timestamp: Date.now(),
      prompt,
      model,
      status: GenerationStatus.PROCESSING,
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    const config: GenerationConfig = {
      apiKey,
      prompt,
      model,
      seconds,
      size,
      watermark,
      startImage,
      endImage,
      endFrameParamName
    };

    addLog({ timestamp: new Date().toLocaleTimeString(), message: `Initializing generation with model: ${model}`, type: 'info' });

    try {
      // This will now await the full polling process
      const responseData = await generateVideo(config, addLog);
      setLastResponse(responseData);

      addLog({ timestamp: new Date().toLocaleTimeString(), message: "Request completed.", type: 'success' });

      // Extract Video URL logic
      let videoUrl: string | undefined = undefined;

      // Try various common paths
      if (responseData.output?.video_url) videoUrl = responseData.output.video_url;
      else if (responseData.video_url) videoUrl = responseData.video_url;
      else if (responseData.url) videoUrl = responseData.url;
      else if (typeof responseData.data === 'string' && responseData.data.startsWith('http')) {
        videoUrl = responseData.data;
      }

      if (videoUrl) {
         setStatus(GenerationStatus.COMPLETED);
         setCurrentVideoUrl(videoUrl);

         setHistory(prev => prev.map(item => 
            item.id === newHistoryId 
              ? { ...item, status: GenerationStatus.COMPLETED, videoUrl } 
              : item
         ));
      } else {
         setStatus(GenerationStatus.COMPLETED); // API finished but no URL found
         addLog({ timestamp: new Date().toLocaleTimeString(), message: "Warning: Video URL not found in response.", type: 'warning' });

         setHistory(prev => prev.map(item => 
            item.id === newHistoryId 
              ? { ...item, status: GenerationStatus.COMPLETED, error: "No direct video URL found" } 
              : item
         ));
      }

    } catch (error: any) {
      setStatus(GenerationStatus.FAILED);
      addLog({ timestamp: new Date().toLocaleTimeString(), message: `Failed: ${error.message}`, type: 'error' });

      setHistory(prev => prev.map(item => 
        item.id === newHistoryId 
          ? { ...item, status: GenerationStatus.FAILED, error: error.message } 
          : item
      ));
    }
  };

  const handleDeleteHistory = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const handleClearHistory = () => {
    if(confirm("Are you sure you want to clear all history?")) {
      setHistory([]);
    }
  };

  const downloadVideo = (url: string, filename: string) => {
    const link = document.createElement('a');
    link.href = url;
    link.target = '_blank';
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const logsEndRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs]);

  return (
    <div className="min-h-screen bg-dark-900 text-white font-sans selection:bg-brand-500/30">

      {/* Header */}
      <header className="bg-dark-800 border-b border-gray-800 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-tr from-brand-600 to-cyan-400 rounded-lg flex items-center justify-center shadow-lg shadow-brand-500/20">
              <Video className="text-white" size={20} />
            </div>
            <div>
              <h1 className="text-lg font-bold tracking-tight">Veo Generator <span className="text-xs font-normal text-brand-400 border border-brand-500/30 px-1.5 py-0.5 rounded ml-2">Preview</span></h1>
              <p className="text-xs text-gray-500">ApiZoo Client</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowSettings(!showSettings)}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border border-gray-700 bg-dark-900 transition hover:bg-dark-800 ${!apiKey ? 'ring-2 ring-red-500/50 animate-pulse' : ''}`}
            >
              <Settings size={16} className={!apiKey ? 'text-red-400' : 'text-gray-400'} />
              <span className="text-sm font-medium text-gray-300">Settings</span>
            </button>
          </div>
        </div>
      </header>

      {/* Settings Panel */}
      {showSettings && (
        <div className="bg-dark-800 border-b border-gray-700 p-6 animate-in slide-in-from-top-2 shadow-2xl relative z-30">
          <div className="max-w-4xl mx-auto">
             <div className="flex flex-col md:flex-row gap-6 items-start">
               <div className="flex-1 w-full">
                  <div className="flex items-center justify-between mb-2">
                    <Label>API Key (Required)</Label>
                    <a 
                      href="https://api.apizoo.top/console/token" 
                      target="_blank" 
                      rel="noreferrer"
                      className="text-xs flex items-center gap-1 text-brand-400 hover:text-brand-300 transition hover:underline"
                    >
                      <Key size={12} />
                      获取 API Key (Get Token) <ExternalLink size={10} />
                    </a>
                  </div>
                  <Input 
                      type="password" 
                      value={apiKey} 
                      onChange={(e) => setApiKey(e.target.value)} 
                      placeholder="sk-..."
                      className={`font-mono text-sm ${!apiKey ? 'border-red-500/50 focus:ring-red-500' : ''}`}
                  />
                  <p className="text-xs text-gray-500 mt-2">
                    Your key is stored locally in your browser. It is never sent to our servers, only to the ApiZoo API.
                  </p>
               </div>
             </div>
          </div>
        </div>
      )}

      <main className="max-w-7xl mx-auto p-4 lg:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Controls */}
        <div className="lg:col-span-5 space-y-6">
          <div className="bg-dark-800 border border-gray-700 rounded-xl p-6 shadow-xl">
            <h2 className="text-xl font-semibold mb-6 flex items-center gap-2">
              <Settings className="text-brand-500" size={20} /> Configuration
            </h2>

            <div className="space-y-5">
              <div>
                <Label>Model</Label>
                <Select value={model} onChange={(e) => setModel(e.target.value)}>
                  {MODEL_OPTIONS.map((m) => (
                    <option key={m} value={m}>{m}</option>
                  ))}
                </Select>
              </div>

              <div>
                <Label>Prompt (提示词)</Label>
                <textarea 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  className="w-full bg-dark-900 border border-gray-700 text-white px-4 py-3 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none h-28 resize-none text-sm leading-relaxed"
                  placeholder="Describe the video you want to generate..."
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                   <Label>Duration (Seconds)</Label>
                   <Select value={seconds} onChange={(e) => setSeconds(e.target.value)}>
                     <option value="5">5 seconds</option>
                     <option value="8">8 seconds</option>
                     <option value="10">10 seconds</option>
                   </Select>
                </div>
                <div>
                   <Label>Aspect Ratio</Label>
                   <Select value={size} onChange={(e) => setSize(e.target.value)}>
                     <option value="16x9">16:9 (Landscape)</option>
                     <option value="9x16">9:16 (Portrait)</option>
                     <option value="1x1">1:1 (Square)</option>
                   </Select>
                </div>
              </div>

              {/* Start Image */}
              <FileUploadZone 
                label="Start Frame (Reference Image)" 
                file={startImage} 
                onChange={setStartImage} 
              />

              {/* End Image */}
              <div className="pt-2 border-t border-gray-700/50">
                 <div className="flex items-center justify-between mb-2">
                    <Label>End Frame (Optional)</Label>
                    <span className="text-xs text-brand-400 bg-brand-900/30 px-2 py-0.5 rounded border border-brand-500/20">Advanced</span>
                 </div>
                 <p className="text-xs text-gray-500 mb-3">
                   Allows creating a transition from Start Frame to End Frame (Image-to-Video).
                 </p>
                 <FileUploadZone 
                    label="End Frame" 
                    file={endImage} 
                    onChange={setEndImage} 
                 />
              </div>

              <button
                onClick={handleGenerate}
                disabled={status === GenerationStatus.PROCESSING || !startImage}
                className={`w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center gap-2 shadow-lg transition transform active:scale-[0.98]
                  ${status === GenerationStatus.PROCESSING 
                    ? 'bg-gray-700 cursor-not-allowed text-gray-400' 
                    : 'bg-gradient-to-r from-brand-600 to-cyan-500 hover:from-brand-500 hover:to-cyan-400 text-white shadow-brand-500/25'
                  }`}
              >
                {status === GenerationStatus.PROCESSING ? (
                  <>
                    <Loader2 className="animate-spin" /> Generating...
                  </>
                ) : (
                  <>
                    <Play fill="currentColor" /> Generate Video
                  </>
                )}
              </button>
            </div>
          </div>
        </div>

        {/* Right Column: Output & Logs */}
        <div className="lg:col-span-7 space-y-6">

          {/* Output Display */}
          <div className="bg-dark-800 border border-gray-700 rounded-xl p-6 min-h-[300px] flex flex-col shadow-xl">
             <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
                <ImageIcon className="text-brand-500" size={20} /> Output Preview
             </h2>

             <div className="flex-1 bg-dark-900/50 rounded-xl border border-dashed border-gray-700 flex items-center justify-center relative overflow-hidden min-h-[400px]">
                {status === GenerationStatus.IDLE && !currentVideoUrl && !lastResponse && (
                  <div className="text-center text-gray-500">
                    <Video size={48} className="mx-auto mb-2 opacity-20" />
                    <p>Ready to generate</p>
                  </div>
                )}

                {status === GenerationStatus.FAILED && (
                   <div className="text-center text-red-400 px-6">
                      <XCircle size={48} className="mx-auto mb-4 opacity-50" />
                      <p className="text-lg font-bold mb-2">Generation Failed</p>
                      <p className="text-sm opacity-80 mb-6">Check logs below for details.</p>
                      <button onClick={() => setStatus(GenerationStatus.IDLE)} className="px-4 py-2 bg-dark-700 hover:bg-dark-600 rounded-lg text-sm">Reset</button>
                   </div>
                )}

                {status === GenerationStatus.PROCESSING && (
                  <div className="text-center w-full max-w-md px-6">
                    <div className="relative w-20 h-20 mx-auto mb-6">
                       <div className="absolute inset-0 border-4 border-brand-900 rounded-full"></div>
                       <div className="absolute inset-0 border-4 border-brand-500 rounded-full border-t-transparent animate-spin"></div>
                       <div className="absolute inset-0 flex items-center justify-center text-xs font-mono text-brand-400">
                         {elapsedTime}s
                       </div>
                    </div>
                    <p className="text-xl font-medium text-white mb-2">Generating Video...</p>
                    <div className="w-full bg-dark-700 rounded-full h-2 mb-4 overflow-hidden">
                       <div 
                         className="h-full bg-gradient-to-r from-brand-600 to-cyan-400 rounded-full transition-all duration-1000 ease-linear"
                         style={{ width: `${Math.min(elapsedTime / 180 * 100, 95)}%` }}
                       />
                    </div>
                    <p className="text-sm text-gray-400 animate-pulse">Waiting for ApiZoo task to complete...</p>
                  </div>
                )}

                {/* If completed but no URL, show debug info */}
                {status === GenerationStatus.COMPLETED && !currentVideoUrl && (
                    <div className="w-full h-full flex flex-col items-center justify-center p-6 text-center">
                        <AlertTriangle className="text-yellow-500 mb-3" size={48} />
                        <h3 className="text-lg font-bold text-white mb-2">Task Completed but Video URL Missing</h3>
                        <p className="text-sm text-gray-400 mb-4">The server reported success, but the app couldn't find a video URL.</p>

                        <div className="w-full bg-black rounded p-3 text-left overflow-auto max-h-[200px] text-xs font-mono border border-gray-800">
                          <pre>{JSON.stringify(lastResponse, null, 2)}</pre>
                        </div>
                    </div>
                )}

                {currentVideoUrl && (
                    <div className="w-full h-full flex flex-col items-center">
                        <video 
                          controls 
                          className="w-full h-auto max-h-[500px] rounded shadow-lg bg-black" 
                          src={currentVideoUrl} 
                          loop 
                          autoPlay 
                          muted 
                        />
                        <div className="mt-4 flex gap-3">
                          <button 
                            onClick={() => downloadVideo(currentVideoUrl!, `veo-video-${Date.now()}.mp4`)}
                            className="flex items-center gap-2 px-4 py-2 bg-brand-600 hover:bg-brand-500 text-white rounded-lg transition shadow-lg"
                          >
                            <Download size={18} /> Download Video
                          </button>
                          <a 
                             href={currentVideoUrl} 
                             target="_blank" 
                             rel="noreferrer"
                             className="flex items-center gap-2 px-4 py-2 bg-dark-700 hover:bg-dark-600 text-gray-300 rounded-lg transition"
                          >
                             Open in New Tab
                          </a>
                        </div>
                    </div>
                )}
             </div>
          </div>

          {/* History Section */}
          <div className="bg-dark-800 border border-gray-700 rounded-xl p-6 shadow-xl">
            <div className="flex items-center justify-between mb-4">
               <h2 className="text-xl font-semibold flex items-center gap-2">
                  <History className="text-brand-500" size={20} /> History
               </h2>
               {history.length > 0 && (
                 <button 
                   onClick={handleClearHistory}
                   className="text-xs text-red-400 hover:text-red-300 flex items-center gap-1"
                 >
                   <Trash2 size={12} /> Clear All
                 </button>
               )}
            </div>

            <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-gray-800">
               {history.length === 0 && (
                 <div className="text-center py-8 text-gray-500 text-sm italic">
                   No generation history yet.
                 </div>
               )}
               {history.map((item) => (
                 <div key={item.id} className="bg-dark-900 border border-gray-800 rounded-lg p-3 flex gap-4 hover:border-brand-500/30 transition group">
                    {/* Status Icon / Thumbnail Placeholder */}
                    <div className="w-24 h-16 shrink-0 bg-black rounded flex items-center justify-center border border-gray-800 overflow-hidden relative">
                       {item.status === GenerationStatus.PROCESSING && (
                         <Loader2 className="animate-spin text-brand-500" size={20} />
                       )}
                       {item.status === GenerationStatus.FAILED && (
                         <XCircle className="text-red-500" size={20} />
                       )}
                       {item.status === GenerationStatus.COMPLETED && (
                          item.videoUrl ? (
                             <video src={item.videoUrl} className="w-full h-full object-cover opacity-80" />
                          ) : (
                             <AlertTriangle className="text-yellow-500" size={20} />
                          )
                       )}
                       {/* Overlay Play Icon */}
                       {item.videoUrl && (
                          <div className="absolute inset-0 flex items-center justify-center bg-black/40 opacity-0 group-hover:opacity-100 transition">
                             <Play size={16} fill="white" className="text-white" />
                          </div>
                       )}
                    </div>

                    <div className="flex-1 min-w-0">
                       <div className="flex justify-between items-start">
                          <p className="text-sm font-medium text-gray-200 truncate">{item.prompt}</p>
                          <button 
                             onClick={() => handleDeleteHistory(item.id)}
                             className="text-gray-600 hover:text-red-400 transition"
                          >
                             <Trash2 size={14} />
                          </button>
                       </div>
                       <div className="flex items-center gap-3 mt-1.5 text-xs text-gray-500">
                          <span className="flex items-center gap-1"><Clock size={10} /> {new Date(item.timestamp).toLocaleTimeString()}</span>
                          <span className="bg-gray-800 px-1.5 py-0.5 rounded text-gray-400">{item.model}</span>
                          <span className={`${
                             item.status === GenerationStatus.COMPLETED ? 'text-green-400' :
                             item.status === GenerationStatus.FAILED ? 'text-red-400' : 'text-brand-400'
                          }`}>
                            {item.status}
                          </span>
                       </div>
                    </div>

                    {item.videoUrl && (
                       <div className="flex flex-col justify-center gap-2">
                          <button 
                             onClick={() => setCurrentVideoUrl(item.videoUrl!)}
                             className="p-1.5 bg-brand-900/30 text-brand-400 hover:bg-brand-900/50 rounded transition"
                             title="Play in Main View"
                          >
                             <Play size={14} />
                          </button>
                          <button 
                             onClick={() => downloadVideo(item.videoUrl!, `veo-${item.id}.mp4`)}
                             className="p-1.5 bg-gray-800 text-gray-400 hover:text-white rounded transition"
                             title="Download"
                          >
                             <Download size={14} />
                          </button>
                       </div>
                    )}
                 </div>
               ))}
            </div>
          </div>

          {/* Terminal / Logs */}
          <div className="bg-black border border-gray-800 rounded-xl p-4 shadow-inner font-mono text-xs h-48 flex flex-col">
             <div className="flex items-center justify-between border-b border-gray-800 pb-2 mb-2">
               <div className="flex items-center gap-2 text-gray-400">
                  <Terminal size={14} />
                  <span>Console Logs</span>
               </div>
               <button onClick={() => setLogs([])} className="text-gray-600 hover:text-gray-300">Clear</button>
             </div>
             <div className="flex-1 overflow-y-auto space-y-1 pr-2 scrollbar-thin scrollbar-thumb-gray-800">
                {logs.length === 0 && <span className="text-gray-700 italic">Waiting for input...</span>}
                {logs.map((log, i) => (
                  <div key={i} className="flex gap-2">
                    <span className="text-gray-600 shrink-0">[{log.timestamp}]</span>
                    <span className={`${
                      log.type === 'error' ? 'text-red-400' :
                      log.type === 'success' ? 'text-green-400' :
                      log.type === 'warning' ? 'text-yellow-400' :
                      'text-blue-300'
                    }`}>
                      {log.type === 'info' && 'ℹ '}
                      {log.type === 'success' && '✔ '}
                      {log.type === 'error' && '✖ '}
                      {log.type === 'warning' && '⚠ '}
                      {log.message}
                    </span>
                  </div>
                ))}
                <div ref={logsEndRef} />
             </div>
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Settings, Play, Terminal, Loader2, Video, ImageIcon, AlertCircle, Download, History, Trash2, Clock, CheckCircle2, XCircle, Key, ExternalLink, AlertTriangle } from 'lucide-react';
import { generateVideo } from './services/apiService';
import { GenerationConfig, LogEntry, GenerationStatus, HistoryItem } from './types';
import { Input, Label, Select, FileUploadZone } from './components/UiComponents';

const MODEL_OPTIONS = [
  "veo_3_1-fast-4K",
  "veo_3_1-components-4K",
  "veo_3_1-4K",
  "veo_3_1-fast-components-4K",
  "veo_3_1",
  "veo_3_1-fast",
  "veo_3_1-components"
];

const App: React.FC = () => {
  // Config State
  const [apiKey, setApiKey] = useState(() => {
    return localStorage.getItem('user_api_key') || "";
  });

  const [model, setModel] = useState(MODEL_OPTIONS[0]);
  const [prompt, setPrompt] = useState("生成视频"); 
  const [seconds, setSeconds] = useState("8");
  const [size, setSize] = useState("16x9");
  const [watermark, setWatermark] = useState("false");
  const [startImage, setStartImage] = useState<File | null>(null);
  const [endImage, setEndImage] = useState<File | null>(null);

  // Advanced Config
  const [endFrameParamName] = useState("input_reference");

  // App State
  // Note: We removed 'status' and 'elapsedTime' to support concurrent tasks. 
  // Status is now tracked per-item in 'history'.
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [currentVideoUrl, setCurrentVideoUrl] = useState<string | null>(null);

  const [showSettings, setShowSettings] = useState(false);

  // History State
  const [history, setHistory] = useState<HistoryItem[]>(() => {
    try {
      const saved = localStorage.getItem('veo_history');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  useEffect(() => {
    localStorage.setItem('veo_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('user_api_key', apiKey);
  }, [apiKey]);

  const addLog = (entry: LogEntry) => {
    setLogs(prev => [...prev, entry]);
  };

  // Helper to update a specific history item
  const updateHistoryItem = (id: string, updates: Partial<HistoryItem>) => {
    setHistory(prev => prev.map(item => 
      item.id === id ? { ...item, ...updates } : item
    ));
  };

  // The actual async task runner
  const runGenerationTask = async (taskId: string, config: GenerationConfig) => {
    const logPrefix = `[Task-${taskId.slice(-4)}]`;

    try {
      const responseData = await generateVideo(config, (log) => {
        // Wrap the log with the task ID so user knows which task is logging
        addLog({ ...log, message: `${logPrefix} ${log.message}` });
      });

      addLog({ timestamp: new Date().toLocaleTimeString(), message: `${logPrefix} Request completed.`, type: 'success' });

      // Extract Video URL logic
      let videoUrl: string | undefined = undefined;

      // Try various common paths
      if (responseData.output?.video_url) videoUrl = responseData.output.video_url;
      else if (responseData.video_url) videoUrl = responseData.video_url;
      else if (responseData.url) videoUrl = responseData.url;
      else if (typeof responseData.data === 'string' && responseData.data.startsWith('http')) {
        videoUrl = responseData.data;
      }

      if (videoUrl) {
         updateHistoryItem(taskId, { status: GenerationStatus.COMPLETED, videoUrl });
         // Automatically play the most recently finished video
         setCurrentVideoUrl(videoUrl);
      } else {
         addLog({ timestamp: new Date().toLocaleTimeString(), message: `${logPrefix} Warning: Video URL not found in response.`, type: 'warning' });
         updateHistoryItem(taskId, { status: GenerationStatus.COMPLETED, error: "No direct video URL found" });
      }

    } catch (error: any) {
      addLog({ timestamp: new Date().toLocaleTimeString(), message: `${logPrefix} Failed: ${error.message}`, type: 'error' });
      updateHistoryItem(taskId, { status: GenerationStatus.FAILED, error: error.message });
    }
  };

  const handleGenerate = () => {
    if (!apiKey) {
      addLog({ timestamp: new Date().toLocaleTimeString(), message: "Error: Please enter your API Key in Settings.", type: 'error' });
      setShowSettings(true); 
      alert("Please enter your API Key first.");
      return;
    }

    if (!startImage) {
      addLog({ timestamp: new Date().toLocaleTimeString(), message: "Error: Start image is required.", type: 'error' });
      return;
    }

    // 1. Setup UI for new task
    const newHistoryId = Date.now().toString();
    const newHistoryItem: HistoryItem = {
      id: newHistoryId,
      timestamp: Date.now(),
      prompt,
      model,
      status: GenerationStatus.PROCESSING,
    };

    // 2. Add to history immediately (Optimistic UI)
    setHistory(prev => [newHistoryItem, ...prev]);

    // 3. Prepare Config
    const config: GenerationConfig = {
      apiKey,
      prompt,
      model,
      seconds,
      size,
      watermark,
      startImage,
      endImage,
      endFrameParamName
    };

    addLog({ timestamp: new Date().toLocaleTimeString(), message: `[Task-${newHistoryId.slice(-4)}] Queued generation task.`, type: 'info' });

    // 4. Start the task WITHOUT awaiting it (Fire and Forget)
    // This allows the UI to remain responsive and the user to start another task.
    runGenerationTask(newHistoryId, config);
  };

  const handleDeleteHistory = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const handleClearHistory = () => {
    if(confirm("Are you sure you want to clear all history?")) {
      setHistory([]);
    }
  };

  const downloadVideo = (url: string, filename: string) => {
    const link = document.createElement('a');
    link.href = url;
    link.target = '_blank';
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const logsEndRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs]);

  return (
    <div className="min-h-screen bg-dark-900 text-white font-sans selection:bg-brand-500/30">

      {/* Header */}
      <header className="bg-dark-800 border-b border-gray-800 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-tr from-brand-600 to-cyan-400 rounded-lg flex items-center justify-center shadow-lg shadow-brand-500/20">
              <Video className="text-white" size={20} />
            </div>
            <div>
              <h1 className="text-lg font-bold tracking-tight">Veo Generator <span className="text-xs font-normal text-brand-400 border border-brand-500/30 px-1.5 py-0.5 rounded ml-2">Preview</span></h1>
              <p className="text-xs text-gray-500">ApiZoo Client</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowSettings(!showSettings)}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border border-gray-700 bg-dark-900 transition hover:bg-dark-800 ${!apiKey ? 'ring-2 ring-red-500/50 animate-pulse' : ''}`}
            >
              <Settings size={16} className={!apiKey ? 'text-red-400' : 'text-gray-400'} />
              <span className="text-sm font-medium text-gray-300">Settings</span>
            </button>
          </div>
        </div>
      </header>

      {/* Settings Panel */}
      {showSettings && (
