import { GenerationConfig, LogEntry } from '../types';

const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper to safely extract error message
const getErrorMessage = (error: any): string => {
  if (!error) return "Unknown Error";
  if (error instanceof Error) return error.message;
  if (typeof error === 'string') return error;

  // Handle objects that might have message or error properties
  if (typeof error === 'object') {
     if (error.message) return String(error.message);
     if (error.error) return String(error.error);
     // If it's a plain object, try to stringify it
     try {
       return JSON.stringify(error);
     } catch (e) {
       return "Object (circular or non-serializable)";
     }
  }
  return String(error);
}

// Helper function to poll the status of the task
const pollTaskStatus = async (
  taskId: string, 
  apiKey: string, 
  onLog: (log: LogEntry) => void
): Promise<any> => {
  const maxAttempts = 120; // Try for about 6 minutes (120 * 3s)
  const interval = 3000; // 3 seconds

  const myHeaders = new Headers();
  myHeaders.append("Accept", "application/json");
  myHeaders.append("Authorization", `Bearer ${apiKey}`);

  const requestOptions: RequestInit = {
    method: 'GET',
    headers: myHeaders,
    redirect: 'follow'
  };

  for (let i = 0; i < maxAttempts; i++) {
    await wait(interval);

    try {
      const response = await fetch(`https://api.apizoo.top/v1/videos/${taskId}`, requestOptions);
      const responseText = await response.text(); // Read text first for debugging/error checking

      // Check for Fatal Errors in raw text (e.g. if API returns plain text error or 4xx with body)
      const lowerText = responseText.toLowerCase();
      if (
          lowerText.includes("public_error") || 
          lowerText.includes("sexual") || 
          lowerText.includes("nsfw") ||
          lowerText.includes("safety_check")
      ) {
         throw new Error(`Fatal API Error: ${responseText}`);
      }

      // Handle HTTP Errors
      if (!response.ok) {
        // 401/403 are fatal authentication errors
        if (response.status === 401 || response.status === 403) {
            throw new Error(`HTTP Authentication Error: ${response.status} ${response.statusText}`);
        }
        // 404 might mean task not found yet (eventual consistency) or wrong ID. 
        // We'll retry a few times but if it persists... (logic handled by loop limit)

        onLog({
          timestamp: new Date().toLocaleTimeString(),
          message: `Polling HTTP Status: ${response.status}. Retrying...`,
          type: 'warning'
        });
        continue;
      }

      let result: any;
      try {
        result = JSON.parse(responseText);
      } catch (e) {
        // If 200 OK but not JSON, and not caught by fatal check above
        throw new Error(`Invalid JSON response: ${responseText.substring(0, 100)}`);
      }

      // Check for API-level Error Codes in JSON
      if (result.code !== undefined && result.code !== 0 && result.code !== 200) {
         throw new Error(result.message || `API Error Code: ${result.code}`);
      }

      // Explicit check for 'message' field indicating failure
      if (typeof result.message === 'string') {
          const upperMsg = result.message.toUpperCase();
          // "PUBLIC_ERROR_SEXUAL" contains "ERROR"
          if (upperMsg.includes('ERROR') || upperMsg.includes('FAIL')) {
              throw new Error(result.message);
          }
      }

      // Determine Status
      const status = (result.status || result.state || '').toLowerCase();
      const progress = result.progress ? ` (${result.progress}%)` : '';

      if (status === 'succeeded' || status === 'completed') {
        onLog({
          timestamp: new Date().toLocaleTimeString(),
          message: `Task Finished!`,
          type: 'success'
        });
        return result; 
      } else if (status === 'failed' || status === 'error') {
        throw new Error(result.message || result.error || "Task failed on server.");
      } else {
        // Still processing
        if (i % 3 === 0) { 
            onLog({
            timestamp: new Date().toLocaleTimeString(),
            message: `Task is ${status || 'processing'}...${progress}`,
            type: 'info'
            });
        }
      }

      // Early exit if video_url exists
      if (result.output?.video_url || result.video_url || result.url) {
        return result;
      }

    } catch (error: any) {
      const errMsg = getErrorMessage(error);
      const lowerMsg = errMsg.toLowerCase();

      // STOP POLLING IMMEDIATELY for these specific errors
      if (
          lowerMsg.includes("public_error") || 
          lowerMsg.includes("sexual") || 
          lowerMsg.includes("safety") || 
          lowerMsg.includes("nsfw") ||
          lowerMsg.includes("illegal") ||
          lowerMsg.includes("http authentication error") || 
          lowerMsg.includes("fatal api error")
      ) {
         throw error; // Rethrow to exit the loop and fail the task
      }

      console.error("Polling error", error);
      onLog({
        timestamp: new Date().toLocaleTimeString(),
        message: `Polling check warning: ${errMsg}`,
        type: 'warning'
      });
    }
  }

  throw new Error("Timeout: Video generation took too long.");
};

export const generateVideo = async (
  config: GenerationConfig,
  onLog: (log: LogEntry) => void
): Promise<any> => {
  const myHeaders = new Headers();
  myHeaders.append("Authorization", `Bearer ${config.apiKey}`);

  const formdata = new FormData();
  formdata.append("model", config.model);
  formdata.append("prompt", config.prompt);
  formdata.append("seconds", config.seconds);
  formdata.append("size", config.size);
  formdata.append("watermark", config.watermark);

  if (config.startImage) {
    onLog({
      timestamp: new Date().toLocaleTimeString(),
      message: `Uploading start frame: ${config.startImage.name}`,
      type: 'info'
    });
    formdata.append("input_reference", config.startImage);
  }

  if (config.endImage) {
    const paramName = config.endFrameParamName || "input_reference";
    onLog({
      timestamp: new Date().toLocaleTimeString(),
      message: `Uploading end frame: ${config.endImage.name}`,
      type: 'info'
    });
    formdata.append(paramName, config.endImage); 
  }

  const requestOptions: RequestInit = {
    method: 'POST',
    headers: myHeaders,
    body: formdata,
    redirect: 'follow'
  };

  onLog({
    timestamp: new Date().toLocaleTimeString(),
    message: 'Submitting task...',
    type: 'info'
  });

  let initialResponse;
  try {
    const response = await fetch("https://api.apizoo.top/v1/videos", requestOptions);
    const text = await response.text();

    if (!response.ok) {
        throw new Error(`Submission Failed (${response.status}): ${text}`);
    }

    try {
        initialResponse = JSON.parse(text);
    } catch(e) {
        throw new Error(`Invalid JSON response from submission: ${text}`);
    }

  } catch (error: any) {
    onLog({ timestamp: new Date().toLocaleTimeString(), message: `Submit Error: ${getErrorMessage(error)}`, type: 'error' });
    throw error;
  }

  const taskId = initialResponse.id || initialResponse.task_id;

  if (taskId) {
    onLog({
        timestamp: new Date().toLocaleTimeString(),
        message: `Task Submitted. ID: ${taskId}`,
        type: 'success'
    });
    return await pollTaskStatus(taskId, config.apiKey, onLog);
  } else if (initialResponse.output?.video_url || initialResponse.data) {
    return initialResponse;
  } else {
    onLog({
        timestamp: new Date().toLocaleTimeString(),
        message: `Warning: No Task ID.`,
        type: 'warning'
    });
    return initialResponse;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Settings, Play, Terminal, Loader2, Video, ImageIcon, AlertCircle, Download, History, Trash2, Clock, CheckCircle2, XCircle, Key, ExternalLink, AlertTriangle } from 'lucide-react';
import { generateVideo } from './services/apiService';
import { GenerationConfig, LogEntry, GenerationStatus, HistoryItem } from './types';
import { Input, Label, Select, FileUploadZone } from './components/UiComponents';

const MODEL_OPTIONS = [
  "veo_3_1-fast-4K",
  "veo_3_1-components-4K",
  "veo_3_1-4K",
  "veo_3_1-fast-components-4K",
  "veo_3_1",
  "veo_3_1-fast",
  "veo_3_1-components"
];

const App: React.FC = () => {
  // Config State
  const [apiKey, setApiKey] = useState(() => {
    return localStorage.getItem('user_api_key') || "";
  });

  const [model, setModel] = useState(MODEL_OPTIONS[0]);
  const [prompt, setPrompt] = useState("生成视频"); 
  const [seconds, setSeconds] = useState("8");
  const [size, setSize] = useState("16x9");
  const [watermark, setWatermark] = useState("false");
  const [startImage, setStartImage] = useState<File | null>(null);
  const [endImage, setEndImage] = useState<File | null>(null);

  // Advanced Config
  const [endFrameParamName] = useState("input_reference");

  // App State
  // Note: We removed 'status' and 'elapsedTime' to support concurrent tasks. 
  // Status is now tracked per-item in 'history'.
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [currentVideoUrl, setCurrentVideoUrl] = useState<string | null>(null);

  const [showSettings, setShowSettings] = useState(false);

  // History State
  const [history, setHistory] = useState<HistoryItem[]>(() => {
    try {
      const saved = localStorage.getItem('veo_history');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  useEffect(() => {
    localStorage.setItem('veo_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('user_api_key', apiKey);
  }, [apiKey]);

  const addLog = (entry: LogEntry) => {
    setLogs(prev => [...prev, entry]);
  };

  // Helper to update a specific history item
  const updateHistoryItem = (id: string, updates: Partial<HistoryItem>) => {
    setHistory(prev => prev.map(item => 
      item.id === id ? { ...item, ...updates } : item
    ));
  };

  // The actual async task runner
  const runGenerationTask = async (taskId: string, config: GenerationConfig) => {
    const logPrefix = `[Task-${taskId.slice(-4)}]`;

    try {
      const responseData = await generateVideo(config, (log) => {
        // Wrap the log with the task ID so user knows which task is logging
        addLog({ ...log, message: `${logPrefix} ${log.message}` });
      });

      addLog({ timestamp: new Date().toLocaleTimeString(), message: `${logPrefix} Request completed.`, type: 'success' });

      // Extract Video URL logic
      let videoUrl: string | undefined = undefined;

      // Try various common paths
      if (responseData.output?.video_url) videoUrl = responseData.output.video_url;
      else if (responseData.video_url) videoUrl = responseData.video_url;
      else if (responseData.url) videoUrl = responseData.url;
      else if (typeof responseData.data === 'string' && responseData.data.startsWith('http')) {
        videoUrl = responseData.data;
      }

      if (videoUrl) {
         updateHistoryItem(taskId, { status: GenerationStatus.COMPLETED, videoUrl });
         // Automatically play the most recently finished video
         setCurrentVideoUrl(videoUrl);
      } else {
         addLog({ timestamp: new Date().toLocaleTimeString(), message: `${logPrefix} Warning: Video URL not found in response.`, type: 'warning' });
         updateHistoryItem(taskId, { status: GenerationStatus.COMPLETED, error: "No direct video URL found" });
      }

    } catch (error: any) {
      // Safely extract error message even if error is not an Error object
      let errorMsg = "Unknown Error";
      if (error instanceof Error) errorMsg = error.message;
      else if (typeof error === 'string') errorMsg = error;
      else if (error && typeof error === 'object') errorMsg = JSON.stringify(error);

      addLog({ timestamp: new Date().toLocaleTimeString(), message: `${logPrefix} Failed: ${errorMsg}`, type: 'error' });
      updateHistoryItem(taskId, { status: GenerationStatus.FAILED, error: errorMsg });
    }
  };

  const handleGenerate = () => {
    if (!apiKey) {
      addLog({ timestamp: new Date().toLocaleTimeString(), message: "Error: Please enter your API Key in Settings.", type: 'error' });
